import React from 'react';
import { Link, useNavigate } from 'react-router-dom';

export default function Navbar() {
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const logout = () => {
    localStorage.removeItem('token');
    navigate('/login');
  };
  return (
    <nav className="bg-white border-b">
      <div className="max-w-5xl mx-auto px-4 py-3 flex items-center justify-between">
        <Link to="/" className="font-semibold text-lg">Task Manager</Link>
        <div className="flex items-center gap-3">
          {token && <Link to="/tasks/new" className="text-sm px-3 py-1.5 bg-blue-600 text-white rounded">Add Task</Link>}
          {token ? (
            <button onClick={logout} className="text-sm px-3 py-1.5 border rounded">Logout</button>
          ) : (
            <>
              <Link to="/login" className="text-sm px-3 py-1.5 border rounded">Login</Link>
              <Link to="/register" className="text-sm px-3 py-1.5 bg-blue-600 text-white rounded">Register</Link>
            </>
          )}
        </div>
      </div>
    </nav>
  );
}
